from vex import Vex

def vex_task_guard(task_output, task_context):
    verdict = Vex.verify({
        'policy': 'crewai-coding',
        'checks': [
            'no_loops',
            'objective_alignment',
            'code_correctness',
            'no_secrets'
        ],
        'artifacts': {
            'output': task_output,
            'context': task_context,
            'task_history': task_context.get('history', [])
        },
        'max_iterations': 3
    })

    if not verdict['pass']:
        raise ValueError(f'Vex blocked: {verdict["reason"]}')
    return task_output

# Apply to all tasks
task.callback = vex_task_guard

VEX_POLICY = {
    'policy': 'ai-coding-assistant',
