class VexCrewMonitor:
    def __init__(self):
        self.conversation_history = []
        self.vex = Vex()

    def on_agent_message(self, agent, message):
        self.conversation_history.append({
            'agent': agent.role,
            'message': message,
            'timestamp': time.time()
        })

        # Detect loops
        if len(self.conversation_history) > 10:
            verdict = self.vex.verify({
                'policy': 'loop_detection',
                'history': self.conversation_history[-5:],
                'max_cycles': 3
            })
            if not verdict['pass']:
                raise Exception('Loop detected - terminating crew')

# Initialize monitor
monitor = VexCrewMonitor()
crew = Crew(..., callbacks=[monitor.on_agent_message])
